/* ─── Helpers ────────────────────────────────────────────────────────────────── */
function completeness(m) {
  const fields = ["nickname","fullname","phone","email","edu","work","family","address","career"];
  const filled = fields.filter(f => m[f]?.trim?.()).length;
  return Math.round(((filled + (m.photoURL ? 1 : 0)) / (fields.length + 1)) * 100);
}
function pctGradient(p) {
  return p === 100
    ? "linear-gradient(90deg,#2e7d32,#4caf50)"
    : "linear-gradient(90deg,#e91e8c,#f06bb0)";
}

